// O template HTML permanece o mesmo (base64) — apenas a função generateReviewHTML é alterada.
// Cole aqui o valor original de REVIEW_TEMPLATE_B64 do seu ficheiro (não alterado).
const REVIEW_TEMPLATE_B64 = '';

function lightenColor(hex: string, factor: number): string {
  const clean = hex.replace('#','');
  const r = parseInt(clean.substring(0,2),16);
  const g = parseInt(clean.substring(2,4),16);
  const b = parseInt(clean.substring(4,6),16);
  const nr = Math.round(r + (255-r)*factor);
  const ng = Math.round(g + (255-g)*factor);
  const nb = Math.round(b + (255-b)*factor);
  return '#' + [nr,ng,nb].map(v=>Math.min(255,v).toString(16).padStart(2,'0')).join('');
}

function darkenColor(hex: string, factor: number): string {
  const clean = hex.replace('#','');
  const r = parseInt(clean.substring(0,2),16);
  const g = parseInt(clean.substring(2,4),16);
  const b = parseInt(clean.substring(4,6),16);
  return '#' + [r,g,b].map(v=>Math.round(v*(1-factor)).toString(16).padStart(2,'0')).join('');
}

// ── Gera o bloco de popup condicionalmente ────────────────────────────────
function buildPopupBlock(popup: any, targetUrl: string): string {
  if (!popup?.enabled) return '';
  return `
<div id="social-proof-popup">
  <a href="${targetUrl}" style="display:block;">
    <div class="popup-inner">
      <img src="{{POPUP_IMAGE}}" class="popup-img" alt="">
      <div>
        <div class="popup-name" id="popup-name">{{POPUP_NAME_1}}</div>
        <div class="popup-city" id="popup-city">{{POPUP_CITY_1}}</div>
        <div class="popup-action"><span class="popup-dot"></span><span id="popup-action-text">{{POPUP_ACTION_TEXT}}</span></div>
      </div>
    </div>
  </a>
</div>`;
}

function buildPopupScript(popup: any, popupNames: string, popupCities: string): string {
  if (!popup?.enabled) return '';
  return `
(function(){
  const popup=document.getElementById('social-proof-popup');
  if(!popup)return;
  const names=[${popupNames}];
  const cities=[${popupCities}];
  function show(){
    const i=Math.floor(Math.random()*Math.min(names.length,cities.length));
    document.getElementById('popup-name').textContent=names[i]||names[0];
    document.getElementById('popup-city').textContent=cities[i]||cities[0];
    popup.style.display='block';
    setTimeout(()=>{popup.style.display='none';},5000);
  }
  setTimeout(show,10000);
  setInterval(show,60000);
})();`;
}

// ── Gera secção Scam com imagem opcional ─────────────────────────────────
function buildScamSection(scamImageUrl: string): string {
  if (!scamImageUrl) return '';
  return `<div class="scam-warning-image" style="margin:16px 0;border-radius:12px;overflow:hidden;">
    <img src="${scamImageUrl}" alt="Warning — only buy from official website" style="width:100%;border-radius:12px;">
  </div>`;
}

// ── Gera secção Pros & Cons com imagem + ratings visuais ─────────────────
function buildProsConsImage(prosCons: any, prosConsImageUrl: string): string {
  if (!prosConsImageUrl) return '';
  return `
<div class="pros-cons-product-visual" style="display:flex;align-items:center;gap:24px;background:var(--gray-50);border:1px solid var(--gray-200);border-radius:var(--radius);padding:24px;margin-bottom:20px;">
  <div style="flex-shrink:0;max-width:160px;">
    <img src="${prosConsImageUrl}" alt="${prosCons?.headline ?? 'Product'}" style="width:100%;border-radius:12px;">
  </div>
  <div style="display:flex;flex-direction:column;gap:8px;">
    ${['Materials','Results','Safety','Quality','Shipping'].map((label, i) => {
      const scores = ['5/5','4.9/5','5/5','5/5','4.8/5'];
      const pct = [100,98,100,100,96];
      return `<div style="display:flex;align-items:center;gap:10px;">
        <span style="font-size:12px;font-weight:700;color:var(--gray-700);width:70px;">${label}</span>
        <div style="flex:1;height:6px;background:var(--gray-200);border-radius:3px;overflow:hidden;">
          <div style="height:100%;width:${pct[i]}%;background:linear-gradient(90deg,var(--primary),var(--primary-dark));border-radius:3px;"></div>
        </div>
        <span style="font-size:12px;font-weight:700;color:var(--primary);width:36px;">${scores[i]}</span>
      </div>`;
    }).join('')}
  </div>
</div>`;
}

// ── Gera badges de certificação ──────────────────────────────────────────
function buildCertBadges(certImageUrl: string): string {
  if (!certImageUrl) return '';
  return `<div class="cert-badges" style="margin-top:20px;text-align:center;">
    <img src="${certImageUrl}" alt="GMP Certified · FDA Registered · GMO-Free · Made in USA" style="max-height:64px;width:auto;margin:0 auto;opacity:.85;">
  </div>`;
}

